const cookDinner_btn=document.getElementById("cookDinner"),meal_container=document.getElementById("recipeContainer");cookDinner_btn.addEventListener("click",()=>{fetch("https://www.themealdb.com/api/json/v1/1/random.php").then(res=>res.json()).then(res=>{createMeal(res.meals[0])})});const createMeal=meal=>{const ingredients=[];for(let i=1;i<=20&&meal[`strIngredient${i}`];i++)ingredients.push(`${meal[`strIngredient${i}`]} - ${meal[`strMeasure${i}`]}`);const newInnerHTML=`\n  <div class="imgContainer">\n    <img src="${meal.strMealThumb}" alt="Meal Image">\n    <h2>${meal.strMeal}</h2>\n  </div>\n\n  <div class="recipeInstructions">\n    <div class="columns ingredient">\n      <h3>Ingredients:</h3>\n      <ul>\n        ${ingredients.map(ingredient=>`<li>${ingredient}</li>`).join("")}\n      </ul>\n      <div class="primaryButton"> \n        <a href="https://www.woolworths.com.au/"> \n          <button>Shop Recipe 🛒</button>\n        </a>\n      </div>\n    </div>\n\n    <div class="columns method">\n      <h3>Method:</h3>\n      <p>${meal.strInstructions.replace(/\r\n/g,"<br><br>")}</p>\n    </div>       \n  </div>\n  ${meal.strYoutube?`\n        <div class="videoRow">\n          <div class="videoWrapper">\n            <iframe src="https://www.youtube.com/embed/${meal.strYoutube.slice(-11)}">\n            </iframe>\n            <div class="searchYoutubeContainer">\n              <p>More videos on Youtube:</p>\n              <div class="primaryButton">\n                <a href="#" id="searchYoutube">\n                  <button>\n                    <svg xmlns="http://www.w3.org/2000/svg" height="30px" viewBox="0 0 576 512"><path d="M549.655 124.083c-6.281-23.65-24.787-42.276-48.284-48.597C458.781 64 288 64 288 64S117.22 64 74.629 75.486c-23.497 6.322-42.003 24.947-48.284 48.597-11.412 42.867-11.412 132.305-11.412 132.305s0 89.438 11.412 132.305c6.281 23.65 24.787 41.5 48.284 47.821C117.22 448 288 448 288 448s170.78 0 213.371-11.486c23.497-6.321 42.003-24.171 48.284-47.821 11.412-42.867 11.412-132.305 11.412-132.305s0-89.438-11.412-132.305zm-317.51 213.508V175.185l142.739 81.205-142.739 81.201z"/>\n                    </svg> ${meal.strMeal}\n                  </button>\n                </a>\n              </div>\n            </div>\n          </div>\n        </div>\n      `:`\n        <h3 class='videoUnavailable'>Video unavailable</h3>\n        <div class="searchYoutubeContainer">\n              <p>More videos on Youtube:</p>\n              <div class="primaryButton">\n                <a href="#" id="searchYoutube">\n                  <button>\n                    <svg xmlns="http://www.w3.org/2000/svg" height="30px" viewBox="0 0 576 512"><path d="M549.655 124.083c-6.281-23.65-24.787-42.276-48.284-48.597C458.781 64 288 64 288 64S117.22 64 74.629 75.486c-23.497 6.322-42.003 24.947-48.284 48.597-11.412 42.867-11.412 132.305-11.412 132.305s0 89.438 11.412 132.305c6.281 23.65 24.787 41.5 48.284 47.821C117.22 448 288 448 288 448s170.78 0 213.371-11.486c23.497-6.321 42.003-24.171 48.284-47.821 11.412-42.867 11.412-132.305 11.412-132.305s0-89.438-11.412-132.305zm-317.51 213.508V175.185l142.739 81.205-142.739 81.201z"/>\n                    </svg> ${meal.strMeal}\n                  </button>\n                </a>\n              </div>\n            </div>\n       `}\n`;meal_container.innerHTML=newInnerHTML,document.getElementById("searchYoutube").addEventListener("click",(function(event){event.preventDefault();const keyword=meal.strMeal,searchUrl=`https://www.youtube.com/results?search_query=${encodeURIComponent(keyword)}`;window.open(searchUrl,"_blank")}))};